 1→import { useState, useCallback } from "react";
 2→import { useLocalization } from "./useLocalization";
 3→import type { WikiArticle } from "../components/WikiCard";
 4→
 5→const preloadImage = (src: string): Promise<void> => {
 6→  return new Promise((resolve, reject) => {
 7→    const img = new Image();
 8→    img.src = src;
 9→    img.onload = () => resolve();
10→    img.onerror = reject;
11→  });
12→};
13→
14→export function useWikiArticles() {
15→  const [articles, setArticles] = useState<WikiArticle[]>([]);
16→  const [loading, setLoading] = useState(false);
17→  const [buffer, setBuffer] = useState<WikiArticle[]>([]);
18→  const { currentLanguage } = useLocalization();
19→
20→  const fetchArticles = async (forBuffer = false) => {
21→    if (loading) return;
22→    setLoading(true);
23→    try {
24→      const response = await fetch(
25→        currentLanguage.api +
26→          new URLSearchParams({
27→            action: "query",
28→            format: "json",
29→            generator: "random",
30→            grnnamespace: "0",
31→            prop: "extracts|info|pageimages",
32→            inprop: "url|varianttitles",
33→            grnlimit: "20",
34→            exintro: "1",
35→            exlimit: "max",
36→            exsentences: "5",
37→            explaintext: "1",
38→            piprop: "thumbnail",
39→            pithumbsize: "800",
40→            origin: "*",
41→            variant: currentLanguage.id,
42→          })
43→      );
44→
45→      const data = await response.json();
46→      const newArticles = Object.values(data.query.pages)
47→        .map(
48→          (page: any): WikiArticle => ({
49→            title: page.title,
50→            displaytitle: page.varianttitles[currentLanguage.id],
51→            extract: page.extract,
52→            pageid: page.pageid,
53→            thumbnail: page.thumbnail,
54→            url: page.canonicalurl,
55→          })
56→        )
57→        .filter(
58→          (article) =>
59→            article.thumbnail &&
60→            article.thumbnail.source &&
61→            article.url &&
62→            article.extract
63→        );
64→
65→      await Promise.allSettled(
66→        newArticles
67→          .filter((article) => article.thumbnail)
68→          .map((article) => preloadImage(article.thumbnail!.source))
69→      );
70→
71→      if (forBuffer) {
72→        setBuffer(newArticles);
73→      } else {
74→        setArticles((prev) => [...prev, ...newArticles]);
75→        fetchArticles(true);
76→      }
77→    } catch (error) {
78→      console.error("Error fetching articles:", error);
79→    }
80→    setLoading(false);
81→  };
82→
83→  const getMoreArticles = useCallback(() => {
84→    if (buffer.length > 0) {
85→      setArticles((prev) => [...prev, ...buffer]);
86→      setBuffer([]);
87→      fetchArticles(true);
88→    } else {
89→      fetchArticles(false);
90→    }
91→  }, [buffer]);
92→
93→  return { articles, loading, fetchArticles: getMoreArticles };
94→}
95→

